var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"물리적인 손상. 면역.","JPN":"物理的な損傷。免疫。","ENG":"Physical damage, Immune.","TWN":"物理損傷，免疫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"TWN":"物理損傷，免疫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"공간 동결 후 붕괴. 면역.","JPN":"空間凍結後崩壊。免疫。","ENG":"Space freeze and collapsing. Immune.","TWN":"空間凍結後崩壞，免疫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"TWN":"空間凍結後崩壞，免疫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_SLASH_BIG_03"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"분자 운동 동결. 면역.","JPN":"分子運動凍結。免疫。","ENG":"Molecular motion freeze. Immune.","TWN":"分子運動凍結，免疫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"TWN":"分子運動凍結，免疫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_SLASH_BIG_02"},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"정보 확산 동결. 면역.","JPN":"情報拡散凍結。免疫。","ENG":"Informational spread freeze. Immune.","TWN":"資訊擴散凍結，免疫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"TWN":"資訊擴散凍結，免疫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_SLASH_BIG_03"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"인지 능력 동결. 면역.","JPN":"認知能力凍結。免疫。","ENG":"Cognitive ability freeze. Immune.","TWN":"認知能力凍結，免疫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"TWN":"認知能力凍結，免疫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"화학 반응 동결. 면역.","JPN":"化学反応凍結。免疫。","ENG":"Chemical reaction freeze. Immune.","TWN":"化學反應凍結，免疫。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"면역. 면역. 면역. 면역─","JPN":"免疫。免疫。免疫。免疫……","ENG":"Immune. Immune. Immune. Immune–","TWN":"免疫，免疫，免疫，免疫——"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>이제 만족하시나요, 레지나 님?</color>","JPN":"<color=#ff3636>もう満足されましたか？　レジーナ様。</color>","ENG":"<color=#ff3636>Are you satisfied now, Miss Regina?</color>","TWN":"<color=#ff3636>現在你滿意了嗎，蕾佳娜？</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>저희의 본질에 이렇게까지 근접하고도 정신이 온전한 인간은 레지나 님이 처음이에요.</color>","JPN":"<color=#ff3636>我々の本質にこれほどまで近づいて、精神が崩れなかった人間はレジーナ様が初めてです。</color>","ENG":"<color=#ff3636>You are the first person to have come this close to our essence while remaining sane.</color>","TWN":"<color=#ff3636>蕾佳娜是第一個如此接近我們的本質卻還精神正常的人。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>하지만 레지나 님은 가엾게도, 세계에 선택받지 못한 인간.</color>","JPN":"<color=#ff3636>ですがレジーナ様は哀れにも、世界に選ばれなかった人間。</color>","ENG":"<color=#ff3636>Unfortunately, Miss Regina... You are a human who is not chosen by the world.</color>","TWN":"<color=#ff3636>但可惜的是，蕾佳娜不是被世界選中的人。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ff3636>신이 만든 규칙을 뛰어넘지 못한다면, 마왕인 저희를 힘으로 소멸시킨다는 건 불가능에 수렴한답니다.</color>","JPN":"<color=#ff3636>神が作った規則を乗り越えることができないかぎり、魔王である我々を力で消滅させることは不可能に近いです。</color>","ENG":"<color=#ff3636>For if you cannot overcome the rule made by god, it is impossible for you to defeat us Demon Lords by force.</color>","TWN":"<color=#ff3636>如果不能跳出神制定的規則，靠力量消滅身為魔王的我們是不可能的。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"TWN":"<color=#ff3636>如果不能跳出神制定的規則，靠力量消滅身為魔王的我們是不可能的。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"전 당신을 쓰러뜨린다고 한 적 없어요, 에델.","JPN":"私はあなたを倒すなど言った覚えはありませんわ、エデル。","ENG":"I never said I was going to defeat you, Edel.","TWN":"我沒說過要打倒你，艾瑟兒。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"연구하겠다고 했죠.","JPN":"研究すると言いました。","ENG":"I said I was going to study you.","TWN":"我說的是研究。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네……?","JPN":"はい……？","ENG":"What...?","TWN":"嗯……？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"저에게 있어 당신은 순수한 정보의 집합체.","JPN":"私にとって、あなたは純粋な情報の集合体。","ENG":"To me, you are a pure collection of information.","TWN":"對我來說，你就是單純的資訊集合體。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"날 것 그대로의 책이나 마찬가지입니다.","JPN":"本そのものと言えます。","ENG":"In other words, you are the same as a book.","TWN":"就和完完整整的書一樣。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그러니 이후로도 계속, 당신의 기만에 혹해 추종자가 될 예정은 없어요.","JPN":"ですからこれからもずっと、あなたの欺瞞に惑わされ、取り巻きになるつもりはありません。","ENG":"Also, after this time, I have no intention of succumbing to your deception and becoming a follower.","TWN":"所以，以後我也一直不打算成為受你欺騙迷惑的追隨者。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"천체의 운행으로 미래를 읽는다고 한다면, 그 원리를 증명하겠습니다.","JPN":"天体の運行で未来を読むとしたら、その原理を証明してみせましょう。","ENG":"If you say you can predict the future by the movements of the celestial bodies, I will try to prove it.","TWN":"如果你用天體的運行來預測未來，那我就證明其原理。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"죽은 자를 살리는 비술을 속삭인다면, 그 실체를 입증하겠어요.","JPN":"死んだ者を蘇らす秘術をささやくなら、その実体を立証してみせましょう。","ENG":"If you whisper you can bring the dead back to the living, I shall confirm its validity.","TWN":"如果你低聲訴說復活死者的秘術，那我就證明其真相。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"만병을 치료하는 약의 제조법이 있다면, 그 모든 성분에 대해 분석해내겠습니다.","JPN":"万病を治す薬の作り方があるなら、そのすべての成分について分析してみせましょう。","ENG":"If there really is medicine that cures all illness, I shall analyze every one of its components.","TWN":"如果有包治百病的藥物製造方法，那我就分析所有成分。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하지만 지금은 열세에 몰려 계시네요, 레지나 님.","JPN":"ですが、今は相変わらずあなたが劣勢です、レジーナ様。","ENG":"But Miss Regina, look at where you’re at.","TWN":"但是現在你處於下風呢，蕾佳娜。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님의 말씀은 듣기만 해도 가슴이 두근거려요.","JPN":"レジーナ様の言葉は聞くだけでドキドキします。","ENG":"Just listening to you makes our hearts flutter.","TWN":"蕾佳娜說的這些話，光是聽著就讓我們心潮澎湃。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"분명 연구되고, 이해된다는 건 저와 같은 존재에게 있어 지고한 쾌락이겠죠.","JPN":"きっと研究され、理解されるというのは我々のような存在にとって至高の快楽でしょう。","ENG":"Surely, it would be more than bliss for something like us to be studied and understood.","TWN":"被研究、被理解，對我這樣的存在來說，就是莫大的快樂。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하지만 평범한 인간인 채로 남아서, 어떻게 그 많은 일을 해내실 생각이죠?","JPN":"しかし普通の人間のままで、どうやってそのようにたくさんのことを成し遂げるおつもりですか？","ENG":"But how do you plan on doing so when you are nothing but an ordinary human?","TWN":"但是作為一個普通人，你打算怎樣去完成這麼多事呢？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"어떻게 그 많은 시간을 견뎌내실 작정이시죠?","JPN":"どうやってその気が遠くなるような時間を耐えるおつもりですか？","ENG":"How are you willing to endure that eternity?","TWN":"你打算怎樣熬過那漫長的歲月呢？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"당장 지금도…… CRF를 상당히 소비하시지 않았나요?","JPN":"今だって……相当なCRFを消耗されていませんか？","ENG":"Even now... You’ve used more than enough CRF.","TWN":"而且現在……就已經消耗了相當多的CRF不是嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"……그렇죠.","JPN":"……そうですわね。","ENG":"...You are right.","TWN":"……沒錯。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"사실대로 말하면, 주민들에게서 받은 기력은 이제 한 줌도 남지 않았어요.","JPN":"正直に言いますと、住民からもらった気力はもう残りわずかです。","ENG":"I admit, there is close to zero power left in me, power that was given by the residents.","TWN":"說實話，我從居民們那裡得到的力量，現在也就只剩下一點點了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":null,"text":{"TWN":"說實話，我從居民們那裡得到的力量，現在也就只剩下一點點了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님……?","JPN":"レジーナ様……？","ENG":"Miss Regina...?","TWN":"蕾佳娜……？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"손가락을 관자놀이에 대는 동작은 무척 공격적인 의미를 내포하고 있답니다.","JPN":"指をこめかみに当てる動作は、とても攻撃的な意味合いを含んでいます。","ENG":"They say the gesture of putting one's finger to the temple implies aggression.","TWN":"把手指放在太陽穴上的動作，蘊含著極具攻擊性的意義。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"저는 생물학에 조예가 부족하지만, 뇌의 대부분이 물이라는 건 잘 압니다.","JPN":"私は生物学についての知識は浅いのですが、脳のほとんどが水であることはよく知っています。","ENG":"While my expertise in biology is limited, I know for a fact that the brain is mainly composed of water.","TWN":"雖然我在生物學方面缺乏造詣，但也知道大腦的大部分都是由水構成的。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"이거라면 아주 작은 힘으로도, 당신이 조치하기 전에 얼음 덩어리로 만들 수 있죠.","JPN":"これならごくわずかな力でも、あなたが何かする前に氷の塊にすることができますわ。","ENG":"I can freeze it using the tiniest spec of power left, before you can do anything.","TWN":"如果是這樣，那麼只需要用很小的力量，我就能在你採取措施之前，把它凍成冰塊。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그런…… 그런 흉측한 농담은 그만두세요, 레지나 님.","JPN":"そんな……そんな怖い冗談はおやめください、レジーナ様。","ENG":"Please... stop making these horrible jokes, Miss Regina.","TWN":"你……請不要開這麼殘酷的玩笑，蕾佳娜。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"협상 테이블에 자기 목숨을 내놓는 것만큼 미련한 짓이 존재할까요?","JPN":"交渉の席に自分の命をさし出すことほど愚かなことがあるのでしょうか。","ENG":"What could be more stupid than putting your own life at risk on the negotiating table?","TWN":"難道還有比把自己的生命放在談判桌上更愚蠢的行為嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"이제까지 저는 당신에게 강제력을 발휘할 수 있는지 실험했어요.","JPN":"今まで私はあなたに強制力を発揮することができるか、試してみました。","ENG":"Up until now, I have been experimenting with whether it is possible to take control of you.","TWN":"之前我已經試過能否對你發揮強制力了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그리고 이제까지의 실험 결과, 당신에게 강제력을 발휘할 수 있는 수단은 이것뿐입니다.","JPN":"そして今までの実験の結果、あなたに強制力を発揮できる手段はこれだけです。","ENG":"It is my conclusion that this is the only way to make you succumb.","TWN":"而之前的試驗結果表明，我能對你發揮強制力的手段就只有這一個。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"당신의 처음이자 마지막이 될.","JPN":"あなたの最初で最後になる。","ENG":"To deprive you of your first and only confidante who understands you.","TWN":"那就是奪走你的第一個，也是最後一個，"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그리고 당신이 처음이자 마지막으로 집착했던 이해자를 박탈하는 것.","JPN":"そして、あなたが最初で最後に執着した理解者を奪うこと。","ENG":"And who you were obsessed with first and only.","TWN":"你在意的第一個，也是最後一個理解者。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"이해되고, 활용되지도 않으면서…….","JPN":"理解され、活用されることもなく……","ENG":"There is nothing more useless than knowledge kept to oneself.","TWN":"再沒有什麼比不被理解、不被利用……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그저 존재할 뿐인 지식만큼 무가치한 것도 없죠.","JPN":"ただ存在するだけの知識ほど無意味なことはありません。","ENG":"Simply existing... without being understood or utilized.","TWN":"只是在虛空中存在的知識更沒價值的了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"이해자가 나타났기에 깨달았을 거예요. 자신이 얼마나 비참한 상태였는지.","JPN":"理解者が現れて気付いたはずです。自分がどれほど哀れな状態であったか。","ENG":"Now, you must realize how miserable you had been because you have found the one who understands you.","TWN":"你是因為出現了理解者才意識到的吧，自己是個多麼悲慘的狀態。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님, 그만두세요. 돌아가셔도 지난번처럼 되살리면 그만이에요.","JPN":"レジーナ様、おやめください。死んでもこの前のように甦らせば済む話です。","ENG":"Miss Regina, stop. Even if you die here, we can just revive you like before.","TWN":"蕾佳娜，請不要再說了。就算你死了，我也只要像上次一樣把你復活就行了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"뇌가 바스라진 뒤에도 가능할지 궁금하네요. 실험해 보죠.","JPN":"脳が砕けた後もできるのか気になりますね。試してみましょう。","ENG":"I wonder if that will still work after my brain has been shattered. Shall we find out?","TWN":"我很好奇腦袋碎掉後還能不能實現，試試看吧。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아직 젊으시잖아요. 사실은 죽기 싫으시면서 겁주지 마세요.","JPN":"まだお若いじゃないですか。実は死にたくないくせに、脅さないでください。","ENG":"You’re still young. Don’t taunt us when you don’t really want to die.","TWN":"你現在還很年輕，其實你也不想死的，所以不要嚇唬我。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"괜찮아요. 당신이 말했잖아요?","JPN":"大丈夫ですわ。あなたも言っていたでしょう？","ENG":"I am not taunting you. You said it yourself, no?","TWN":"沒關係，你不是說了嘛？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"감정을 동결시켰어요. 저는 지금 철저하게 이성적입니다.","JPN":"感情を凍結させました。私は今、しごく理性的です。","ENG":"I have frozen my emotions. Right now, I am completely rational.","TWN":"我凍結了感情。我現在是完全理性的狀態。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"TWN":"我凍結了感情。我現在是完全理性的狀態。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"돌이켜 보세요. 이게 정말 레지나 님의 진심일까요?","JPN":"振り返ってみてください。これが本当にレジーナ様の本心でしょうか？","ENG":"Take a look at yourself. Do you really think this is what you want, Miss Regina?","TWN":"你回頭看看，這真的是蕾佳娜的真心嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"누군가가 부채질한 것 아닌가요?","JPN":"誰かに煽られたのではありませんか？","ENG":"Don’t you think someone might have taken advantage of you?","TWN":"不是受人煽動嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"서로의 이익이 일치한다면 부채질 정도는 당해 줄 수 있죠. 상관없습니다.","JPN":"お互いの利害が一致するなら、煽られてあげますわ。構いません。","ENG":"I would not mind getting used, as long as it is mutually beneficial.","TWN":"如果彼此的利益一致，那麼也可以受人煽動。我無所謂。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저처럼 되면 수명도 죽음도 두려워할 필요가 없어요.","JPN":"我々のようになれば、寿命や死を恐れなくてもいいんです。","ENG":"If you become one of us, you wouldn’t have to worry about death.","TWN":"變成我這樣以後，就不需要再擔心壽命或死亡了。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님도 결국 안나 부인처럼 영생에 매달리실 텐데요?","JPN":"レジーナ様も結局、アンナ夫人のように永生にすがりつくようになりますよ？","ENG":"You will follow the life of your mother, Miss Regina.","TWN":"蕾佳娜最後也會變得像安娜夫人一樣執著於永生吧？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그럼 지금 죽어야겠군요. 어머니처럼 늙어서 추해질 바에야 그 편이 낫죠.","JPN":"それならば、今ここで死ぬべきですね。お母様のように年老いて醜くなるくらいなら、その方がマシですわ。","ENG":"Then I must die now. I cannot let myself grow old and foul like her.","TWN":"那我選擇現在就直接死掉。與其像母親那樣變老變醜，還不如現在就死掉。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"대체…","JPN":"いったい……","ENG":"What...","TWN":"你到底……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"대체 뭘 원하시는 거예요?","JPN":"いったい何が欲しいのですか？","ENG":"What is it that you really want?","TWN":"你到底想要什麼？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"영생? 불멸? 부와 명예? 정말 학회장직이 갖고 싶어서 이러시나요?","JPN":"永生？　不滅？　富と名誉？　本当に学会長の座が欲しくてこのようなことをされているのですか？","ENG":"Eternal life? Youth? Money and fame? Or the status of President?","TWN":"永生？不死？財富與榮譽？你真的是因為想要學會長的位置才這樣的嗎？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"갑자기 바보가 됐네요, 에델.","JPN":"いきなりバカになりましたわね、エデル。","ENG":"You sound like a fool, Edel.","TWN":"你突然變成傻瓜了呢，艾瑟兒。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"당신이에요.","JPN":"あなたです。","ENG":"I want you.","TWN":"我想要你。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"……!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"TWN":"……！"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"역대 학회장들이 그러했듯, 저 역시 지식의 호수를 취할 겁니다.","JPN":"歴代の学会長がそうだったように、私もまた知識の湖を手に入れます。","ENG":"As all previous presidents have tried to do so, I too shall make the Lake of Knowledge mine.","TWN":"就像歷任學會長那樣，我也想要得到知識湖水。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_1"},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"하지만 어리석은 선조들처럼 당신을 맹종할 생각은 털끝만큼도 없어요.","JPN":"ですが、愚かな先祖たちのようにあなたに盲従するつもりはこれっぽちもありません。","ENG":"However, unlike my foolish ancestors... I have no intention of abiding by you.","TWN":"但是我完全沒有像愚蠢的祖先們那樣盲從於你的想法。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_2-2"},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"자, 저와 함께 영지로 돌아가죠. 에델.","JPN":"さあ、私とともに領地に戻りましょう。エデル。","ENG":"Now, come back to the estate with me, Edel.","TWN":"來，跟我一起回領地吧，艾瑟兒。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_3"},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그 곳에서 당신이 지닌 모든 것을 하나하나, 모조리.","JPN":"そこであなたが持っているすべてを一つひとつ。","ENG":"There, I will analyze, understand, and prove...","TWN":"我會在那裡，把你擁有的一切，"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_4"},{"id":"L30_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"분석하고 이해한 끝에 증명해서, 정복하겠어요.","JPN":"分析し、理解し、そして証明して、征服しますわ。","ENG":"Every single detail about you, until the day I conquer you.","TWN":"逐一分析、理解，最後證明並征服。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_5"},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"영겁의 시간이 걸려도 상관없습니다.","JPN":"気が遠くなるような時間がかかっても構いません。","ENG":"I do not care how long it will take.","TWN":"就算花上極其漫長的歲月也沒關係。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_6"},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그렇게 해서…… 당신을 제 것으로 만들고 말겠어요.","JPN":"そうして……あなたを私のものにしてみせます。","ENG":"My only wish... is to make you mine.","TWN":"我要那樣……把你變成我的所有物。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_7"},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그러니 제 것이 되세요. 영원히.","JPN":"ですから、私のものになりなさい。永遠に。","ENG":"So, be mine. Forever.","TWN":"所以，成為我的所有物吧，永遠地。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ESPR_CA_FROZEN_IN_TRAILER_8"},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"네, 레지나 님. 기꺼이.","JPN":"はい、レジーナ様。喜んで。","ENG":"Yes, Miss Regina. As you wish.","TWN":"好的，蕾佳娜，我樂意至極。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_ESPR_SHADOW_TRAILER_1"},{"id":"L36_1","type":"dialog","speaker":null,"text":{"TWN":"好的，蕾佳娜，我樂意至極。"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};